--
-- Name: addattendance(integer, integer, integer, integer, integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.addattendance(IN p_student_id integer, IN p_discipline_id integer, IN p_period_id integer, IN p_attended_count integer, IN p_missed_count integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_attended_count < 0 OR p_missed_count < 0 THEN
        RAISE EXCEPTION 'Количество посещенных и пропущенных занятий не может быть отрицательным.';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM Students WHERE ID_Student = p_student_id) THEN
        RAISE EXCEPTION 'Студент с идентификатором % не найден.', p_student_id;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM Disciplines WHERE ID_Discipline = p_discipline_id) THEN
        RAISE EXCEPTION 'Дисциплина с идентификатором % не найдена.', p_discipline_id;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM StudyPeriods WHERE ID_Period = p_period_id) THEN
        RAISE EXCEPTION 'Учебный период с идентификатором % не найден.', p_period_id;
    END IF;

        AttendedCount,
        MissedCount,
        Student_ID,
        Discipline_ID,
        Period_ID
    )
    VALUES (
        p_attended_count,
        p_missed_count,
        p_student_id,
        p_discipline_id,
        p_period_id
    );
END;
$$;


--
-- Name: addgrade(integer, integer, integer, integer, character varying, date); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.addgrade(IN p_student_id integer, IN p_discipline_id integer, IN p_period_id integer, IN p_grade_value integer, IN p_control_type character varying, IN p_grade_date date)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF p_grade_value NOT BETWEEN 2 AND 5 THEN
        RAISE EXCEPTION 'Оценка должна быть в диапазоне от 2 до 5.';
    END IF;

    IF NOT EXISTS (SELECT 1 FROM Students WHERE ID_Student = p_student_id) THEN
        RAISE EXCEPTION 'Студент с идентификатором % не найден.', p_student_id;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM Disciplines WHERE ID_Discipline = p_discipline_id) THEN
        RAISE EXCEPTION 'Дисциплина с идентификатором % не найдена.', p_discipline_id;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM StudyPeriods WHERE ID_Period = p_period_id) THEN
        RAISE EXCEPTION 'Учебный период с идентификатором % не найден.', p_period_id;
    END IF;

        GradeValue,
        ControlType,
        GradeDate,
        Student_ID,
        Discipline_ID,
        Period_ID
    )
    VALUES (
        p_grade_value,
        p_control_type,
        COALESCE(p_grade_date, CURRENT_DATE),
        p_student_id,
        p_discipline_id,
        p_period_id
    );
END;
$$;


--
-- Name: addstudent(character varying, character varying, character varying, character varying, integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.addstudent(IN p_last_name character varying, IN p_first_name character varying, IN p_patronymic character varying, IN p_record_book_number character varying, IN p_group_id integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM StudyGroups WHERE ID_Group = p_group_id) THEN
        RAISE EXCEPTION 'Учебная группа с идентификатором % не найдена.', p_group_id;
    END IF;

    VALUES (p_last_name, p_first_name, p_patronymic, p_record_book_number, p_group_id);
END;
$$;


