--

CREATE FUNCTION public.check_account_email() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.Email NOT LIKE '%@%' THEN
        RAISE EXCEPTION 'Некорректный адрес электронной почты: должен содержать символ @.';
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: check_attendance_values(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_attendance_values() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.AttendedCount < 0 OR NEW.MissedCount < 0 THEN
        RAISE EXCEPTION 'Количество посещенных и пропущенных занятий не может быть отрицательным.';
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: checkuserpassword(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.checkuserpassword(p_email character varying, p_password character varying) RETURNS TABLE(account_id integer, email character varying, role_name character varying, is_blocked boolean, last_name character varying, first_name character varying, patronymic character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        a.ID_Account,
        a.Email,
        r.RoleName,
        a.IsBlocked,
        u.LastName,
        u.FirstName,
        u.Patronymic
    FROM Accounts a
    JOIN Roles r ON a.Role_ID = r.ID_Role
    JOIN Users u ON u.Account_ID = a.ID_Account
    WHERE a.Email = p_email
      AND a.PasswordHash = crypt(p_password, a.PasswordHash);
END;
$$;


--
-- Name: get_grade_distribution(integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_grade_distribution(p_group_id integer, p_discipline_id integer, p_period_id integer) RETURNS TABLE(grade_label character varying, grade_count bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        g.GradeValue::VARCHAR AS grade_label,
        COUNT(g.ID_Grade) AS grade_count
    FROM Grades g
    JOIN Students s ON g.Student_ID = s.ID_Student
    WHERE s.Group_ID = p_group_id
      AND g.Discipline_ID = p_discipline_id
      AND g.Period_ID = p_period_id
    GROUP BY g.GradeValue
    ORDER BY g.GradeValue DESC;
END;
$$;


--
-- Name: get_group_attendance_rate_period(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_group_attendance_rate_period(p_group_id integer, p_period_id integer) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    attendance_rate NUMERIC;
BEGIN
    SELECT ROUND(
        AVG(
            CASE
                WHEN (a.AttendedCount + a.MissedCount) = 0 THEN 0
                ELSE a.AttendedCount::NUMERIC / (a.AttendedCount + a.MissedCount) * 100
            END
        ),
        2
    )
    INTO attendance_rate
    FROM Attendance a
    JOIN Students s ON a.Student_ID = s.ID_Student
    WHERE s.Group_ID = p_group_id
      AND a.Period_ID = p_period_id;

    RETURN COALESCE(attendance_rate, 0);
END;
$$;


--
-- Name: get_group_avg_grade_period(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_group_avg_grade_period(p_group_id integer, p_period_id integer) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    avg_grade NUMERIC;
BEGIN
    SELECT ROUND(AVG(g.GradeValue), 2)
    INTO avg_grade
    FROM Grades g
    JOIN Students s ON g.Student_ID = s.ID_Student
    WHERE s.Group_ID = p_group_id
      AND g.Period_ID = p_period_id;

    RETURN COALESCE(avg_grade, 0);
END;
$$;


--
-- Name: get_group_success_rate_period(integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_group_success_rate_period(p_group_id integer, p_period_id integer) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    success_rate NUMERIC;
BEGIN
    SELECT ROUND(
        CASE
            WHEN COUNT(g.ID_Grade) = 0 THEN 0
            ELSE COUNT(g.ID_Grade) FILTER (WHERE g.GradeValue >= 3)::NUMERIC / COUNT(g.ID_Grade) * 100
        END,
        2
    )
    INTO success_rate
    FROM Grades g
    JOIN Students s ON g.Student_ID = s.ID_Student
    WHERE s.Group_ID = p_group_id
      AND g.Period_ID = p_period_id;

    RETURN COALESCE(success_rate, 0);
END;
$$;


--
-- Name: log_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_changes() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    key_field TEXT;
    key_value INT;
    current_account_id INT;
BEGIN
    SELECT column_name
    INTO key_field
    FROM information_schema.columns
    WHERE table_name = TG_TABLE_NAME
      AND column_name ILIKE 'id_%'
    ORDER BY ordinal_position
    LIMIT 1;

    BEGIN
        current_account_id := NULLIF(current_setting('app.current_account_id', true), '')::INT;
    EXCEPTION
        WHEN OTHERS THEN
            current_account_id := NULL;
    END;

    IF TG_OP = 'INSERT' THEN
        EXECUTE format('SELECT ($1).%I', key_field)
        INTO key_value
        USING NEW;

            ActionName,
            EntityName,
            EntityID,
            OldValue,
            NewValue,
            Account_ID
        )
        VALUES (
            'INSERT',
            TG_TABLE_NAME,
            key_value,
            NULL,
            row_to_json(NEW)::JSONB,
            current_account_id
        );

        RETURN NEW;

    ELSIF TG_OP = 'UPDATE' THEN
        EXECUTE format('SELECT ($1).%I', key_field)
        INTO key_value
        USING NEW;

            ActionName,
            EntityName,
            EntityID,
            OldValue,
            NewValue,
            Account_ID
        )
        VALUES (
            'UPDATE',
            TG_TABLE_NAME,
            key_value,
            row_to_json(OLD)::JSONB,
            row_to_json(NEW)::JSONB,
            current_account_id
        );

        RETURN NEW;

    ELSIF TG_OP = 'DELETE' THEN
        EXECUTE format('SELECT ($1).%I', key_field)
        INTO key_value
        USING OLD;

            ActionName,
            EntityName,
            EntityID,
            OldValue,
            NewValue,
            Account_ID
        )
        VALUES (
            'DELETE',
            TG_TABLE_NAME,
            key_value,
            row_to_json(OLD)::JSONB,
            NULL,
            current_account_id
        );

        RETURN OLD;
    END IF;

    RETURN NULL;
END;
$_$;


--
-- Name: registeruser(character varying, character varying, character varying, character varying, character varying); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.registeruser(IN p_email character varying, IN p_password character varying, IN p_last_name character varying, IN p_first_name character varying, IN p_patronymic character varying)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_account_id INT;
    v_role_id INT;
BEGIN
    IF length(trim(p_email)) = 0 THEN
        RAISE EXCEPTION 'Электронная почта не может быть пустой.';
    END IF;

    IF p_email NOT LIKE '%@%' THEN
        RAISE EXCEPTION 'Некорректный адрес электронной почты.';
    END IF;

    IF length(p_password) < 8 THEN
        RAISE EXCEPTION 'Пароль должен содержать не менее 8 символов.';
    END IF;

    IF EXISTS (SELECT 1 FROM Accounts WHERE Email = p_email) THEN
        RAISE EXCEPTION 'Пользователь с электронной почтой % уже существует.', p_email;
    END IF;

    SELECT ID_Role INTO v_role_id
    FROM Roles
    WHERE RoleName = 'Пользователь';

    IF v_role_id IS NULL THEN
        RAISE EXCEPTION 'Роль Пользователь не найдена.';
    END IF;

    VALUES (
        p_email,
        crypt(p_password, gen_salt('bf', 12)),
        v_role_id
    )
    RETURNING ID_Account INTO v_account_id;

    VALUES (p_last_name, p_first_name, p_patronymic, v_account_id);
END;
$$;


--
-- Name: saveinfographic(character varying, character varying, jsonb, jsonb, integer, integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.saveinfographic(IN p_title character varying, IN p_chart_type character varying, IN p_parameters jsonb, IN p_result_data jsonb, IN p_account_id integer, IN p_template_id integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM Accounts WHERE ID_Account = p_account_id) THEN
        RAISE EXCEPTION 'Аккаунт с идентификатором % не найден.', p_account_id;
    END IF;

    IF EXISTS (
        SELECT 1
        FROM Accounts
        WHERE ID_Account = p_account_id
          AND IsBlocked = TRUE
    ) THEN
        RAISE EXCEPTION 'Аккаунт с идентификатором % заблокирован. Сохранение инфографики запрещено.', p_account_id;
    END IF;

    IF p_template_id IS NOT NULL
       AND NOT EXISTS (SELECT 1 FROM InfographicTemplates WHERE ID_Template = p_template_id) THEN
        RAISE EXCEPTION 'Шаблон инфографики с идентификатором % не найден.', p_template_id;
    END IF;

    IF p_chart_type NOT IN ('bar', 'line', 'pie', 'doughnut', 'card') THEN
        RAISE EXCEPTION 'Недопустимый тип диаграммы.';
    END IF;

        Title,
        ChartType,
        Parameters,
        ResultData,
        Account_ID,
        Template_ID
    )
    VALUES (
        p_title,
        p_chart_type,
        p_parameters,
        p_result_data,
        p_account_id,
        p_template_id
    );
END;
$$;


--
-- Name: setaccountblockstatus(integer, boolean); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.setaccountblockstatus(IN p_account_id integer, IN p_is_blocked boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM Accounts WHERE ID_Account = p_account_id) THEN
        RAISE EXCEPTION 'Аккаунт с идентификатором % не найден.', p_account_id;
    END IF;

    UPDATE Accounts
    SET IsBlocked = p_is_blocked
    WHERE ID_Account = p_account_id;
END;
$$;


--
-- Name: setaccountrole(integer, integer); Type: PROCEDURE; Schema: public; Owner: -
--

CREATE PROCEDURE public.setaccountrole(IN p_account_id integer, IN p_role_id integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM Accounts WHERE ID_Account = p_account_id) THEN
        RAISE EXCEPTION 'Аккаунт с идентификатором % не найден.', p_account_id;
    END IF;

    IF NOT EXISTS (SELECT 1 FROM Roles WHERE ID_Role = p_role_id) THEN
        RAISE EXCEPTION 'Роль с идентификатором % не найдена.', p_role_id;
    END IF;

    UPDATE Accounts
    SET Role_ID = p_role_id
    WHERE ID_Account = p_account_id;
END;
$$;


