--
-- Name: attendanceview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.attendanceview AS
 SELECT a.id_attendance AS "Код посещаемости",
    (((((s.lastname)::text || ' '::text) || (s.firstname)::text) || ' '::text) || (COALESCE(s.patronymic, ''::character varying))::text) AS "Студент",
    sg.groupname AS "Группа",
    d.disciplinename AS "Дисциплина",
    sp.studyyear AS "Учебный год",
    sp.semester AS "Семестр",
    a.attendedcount AS "Посещено занятий",
    a.missedcount AS "Пропущено занятий",
    (a.attendedcount + a.missedcount) AS "Всего занятий",
    round(
        CASE
            WHEN ((a.attendedcount + a.missedcount) = 0) THEN (0)::numeric
            ELSE (((a.attendedcount)::numeric / ((a.attendedcount + a.missedcount))::numeric) * (100)::numeric)
        END, 2) AS "Процент посещаемости"
   FROM ((((public.attendance a
     JOIN public.students s ON ((a.student_id = s.id_student)))
     JOIN public.studygroups sg ON ((s.group_id = sg.id_group)))
     JOIN public.disciplines d ON ((a.discipline_id = d.id_discipline)))
     JOIN public.studyperiods sp ON ((a.period_id = sp.id_period)));


