--
-- Name: auditlogview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.auditlogview AS
 SELECT al.id_auditlog AS "Код записи",
    al.actionname AS "Действие",
    al.entityname AS "Таблица",
    al.entityid AS "Код записи таблицы",
    al.oldvalue AS "Старое значение",
    al.newvalue AS "Новое значение",
    al.actiondate AS "Дата действия",
    a.id_account AS "Код аккаунта",
    a.email AS "Email пользователя",
    r.rolename AS "Роль пользователя",
        CASE
            WHEN (a.id_account IS NULL) THEN 'Система'::text
            WHEN (TRIM(BOTH FROM (((((COALESCE(u.lastname, ''::character varying))::text || ' '::text) || (COALESCE(u.firstname, ''::character varying))::text) || ' '::text) || (COALESCE(u.patronymic, ''::character varying))::text)) = ''::text) THEN (a.email)::text
            ELSE TRIM(BOTH FROM (((((COALESCE(u.lastname, ''::character varying))::text || ' '::text) || (COALESCE(u.firstname, ''::character varying))::text) || ' '::text) || (COALESCE(u.patronymic, ''::character varying))::text))
        END AS "Пользователь"
   FROM (((public.auditlog al
     LEFT JOIN public.accounts a ON ((al.account_id = a.id_account)))
     LEFT JOIN public.users u ON ((u.account_id = a.id_account)))
     LEFT JOIN public.roles r ON ((a.role_id = r.id_role)))
  WHERE ((a.id_account IS NULL) OR (a.isblocked = false));


