--
-- Name: gradesview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.gradesview AS
 SELECT gr.id_grade AS "Код оценки",
    (((((s.lastname)::text || ' '::text) || (s.firstname)::text) || ' '::text) || (COALESCE(s.patronymic, ''::character varying))::text) AS "Студент",
    sg.groupname AS "Группа",
    d.disciplinename AS "Дисциплина",
    sp.studyyear AS "Учебный год",
    sp.semester AS "Семестр",
    gr.gradevalue AS "Оценка",
    gr.controltype AS "Форма контроля",
    gr.gradedate AS "Дата оценки"
   FROM ((((public.grades gr
     JOIN public.students s ON ((gr.student_id = s.id_student)))
     JOIN public.studygroups sg ON ((s.group_id = sg.id_group)))
     JOIN public.disciplines d ON ((gr.discipline_id = d.id_discipline)))
     JOIN public.studyperiods sp ON ((gr.period_id = sp.id_period)));


--
-- Name: groupstatisticsview; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.groupstatisticsview AS
 WITH studentcounts AS (
         SELECT sg_1.id_group,
            count(s.id_student) AS studentscount
           FROM (public.studygroups sg_1
             LEFT JOIN public.students s ON ((sg_1.id_group = s.group_id)))
          GROUP BY sg_1.id_group
        ), gradestats AS (
         SELECT sg_1.id_group,
            round(avg(g.gradevalue), 2) AS averagegrade,
            round(
                CASE
                    WHEN (count(g.id_grade) = 0) THEN (0)::numeric
                    ELSE (((count(g.id_grade) FILTER (WHERE (g.gradevalue >= 3)))::numeric / (count(g.id_grade))::numeric) * (100)::numeric)
                END, 2) AS successrate,
            count(DISTINCT s.id_student) FILTER (WHERE (g.gradevalue = 2)) AS debtorcount,
            count(DISTINCT s.id_student) FILTER (WHERE (g.gradevalue = 5)) AS excellentcount
           FROM ((public.studygroups sg_1
             LEFT JOIN public.students s ON ((sg_1.id_group = s.group_id)))
             LEFT JOIN public.grades g ON ((s.id_student = g.student_id)))
          GROUP BY sg_1.id_group
        ), attendancestats AS (
         SELECT sg_1.id_group,
            round(avg(
                CASE
                    WHEN ((a.attendedcount + a.missedcount) = 0) THEN (0)::numeric
                    ELSE (((a.attendedcount)::numeric / ((a.attendedcount + a.missedcount))::numeric) * (100)::numeric)
                END), 2) AS attendancerate
           FROM ((public.studygroups sg_1
             LEFT JOIN public.students s ON ((sg_1.id_group = s.group_id)))
             LEFT JOIN public.attendance a ON ((s.id_student = a.student_id)))
          GROUP BY sg_1.id_group
        )
 SELECT sg.id_group AS "Код группы",
    sg.groupname AS "Группа",
    sg.course AS "Курс",
    sg.studyyear AS "Учебный год",
    sc.studentscount AS "Количество студентов",
    COALESCE(gs.averagegrade, (0)::numeric) AS "Средний балл",
    COALESCE(gs.successrate, (0)::numeric) AS "Процент успеваемости",
    COALESCE(gs.debtorcount, (0)::bigint) AS "Количество задолженностей",
    COALESCE(gs.excellentcount, (0)::bigint) AS "Количество отличников",
    COALESCE(ast.attendancerate, (0)::numeric) AS "Средний процент посещаемости"
   FROM (((public.studygroups sg
     JOIN studentcounts sc ON ((sg.id_group = sc.id_group)))
     JOIN gradestats gs ON ((sg.id_group = gs.id_group)))
     JOIN attendancestats ast ON ((sg.id_group = ast.id_group)));


