CREATE VIEW public.studentstatisticsview AS
 SELECT s.id_student AS "Код студента",
    (((((s.lastname)::text || ' '::text) || (s.firstname)::text) || ' '::text) || (COALESCE(s.patronymic, ''::character varying))::text) AS "ФИО студента",
    sg.groupname AS "Группа",
    round(avg(g.gradevalue), 2) AS "Средний балл",
    count(g.id_grade) AS "Количество оценок",
    count(g.id_grade) FILTER (WHERE (g.gradevalue = 5)) AS "Количество отличных оценок",
    count(g.id_grade) FILTER (WHERE (g.gradevalue = 2)) AS "Количество неудовлетворительных "
   FROM ((public.students s
     JOIN public.studygroups sg ON ((s.group_id = sg.id_group)))
     LEFT JOIN public.grades g ON ((s.id_student = g.student_id)))
  GROUP BY s.id_student, s.lastname, s.firstname, s.patronymic, sg.groupname;


